#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

#define N_CHILDREN 3

int main(void) {
    setbuf(stdout, NULL);
    pid_t pids[N_CHILDREN];

    for (int i = 0; i < N_CHILDREN; i++) {
        pids[i] = fork();
        if (pids[i] == -1) { perror("fork"); return 1; }
        if (pids[i] == 0) {
            printf("Child %d: PID=%d\n", i + 1, getpid());
            _exit(i + 1); /* code de sortie = numéro */
        }
    }

    /* Parent attend chaque enfant dans l'ordre */
    for (int i = 0; i < N_CHILDREN; i++) {
        int status;
        waitpid(pids[i], &status, 0);
        if (WIFEXITED(status))
            printf("Parent: child %d exited with %d\n", i + 1, WEXITSTATUS(status));
    }

    return 0;
}

